INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-64311456-moex-00475', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '「愛爾蘭劇作家蕭伯納說：『我有一顆蘋果，你也有一顆蘋果，交換之後，我們還是各自擁 有一顆蘋果；但如果我有一個觀念，你也有一個觀念，交流之後，我們都各擁有兩個觀念。』 資訊和知識、才能與資源的分享，讓當事人的知識和觀念加倍成長，這是人際關係中非常珍 貴的互惠原則。來源不同的觀念知能和才氣資源，在互惠分享和交流碰撞中，可以因新奇組 合而產生創意。」 根據上文，下列選項何者正確？', '["交流觀念和交換蘋果的結果是一樣的", "致力拓展人脈，可以利用彼此的資源，具有加倍效應", "吸收新奇的觀點，是彼此知識互惠交流所追求的重要目標", "人的知能與才氣不同，往往可以在互惠交流過程中產生創意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00476', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '張處長榮獲模範父親表揚，同仁們擬贈匾祝賀，下列選項中的題辭何者正確？', '["教澤長存", "春暉廣被", "忠孝傳家", "壽元無量 明倫教孝"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00477', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '下列各選項皆出自一篇有關親子關係與青少年心理學的論述，「 」內的詞語應用正確的是：', '["親子衝突帶來的負面情緒，容易造成青少年不同類型的負面情緒，「導致」不同的問題行為", "多數父母掌控生活資源，若常採用「嚴厲」的懲罰手段，可能讓孩子產生威脅感，陷入焦 慮不安", "父母親在不自覺中的情緒勒索，會讓青少年「滋養」愧疚感，引發青少年退縮、缺乏自信、 自我孤立", "青少年階段是情緒的暴風時期，如果自尊受損，在無法「調配」控制下，可能轉而用攻擊 行為宣洩情緒 當青少年長期感受到委屈、冤枉，或因為處處受到父母的「管控」，最後可能選擇壓抑自 己而萌生怨恨感"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00478', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '「要使這個社會治安趨於良好，最重要的是勸導那些不法之徒，能夠□□□□。」 下列成語，何者適合填入空格內？', '["明辨是非", "不念舊惡", "遷善改過", "除舊布新 洗心革面"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00479', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '下列文句「」中的成語，運用正確的是：', '["父親教導我們默默行善，以免有「沽名釣譽」之嫌", "警方鎖定的陳姓嫌犯「危言危行」，民眾十分恐慌", "具創造力的人常「見異思遷」，能不斷開發新產品", "張局長高瞻遠矚，總是能「見微知著」，超前部署 比賽選手個個舌粲蓮花，「信口開河」的進行演說"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00480', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '「天地間有些東西沒有主人，例如自然美景。既然無主，我們可以盡情享有，大自然不加限 制。審美的能力是先天稟賦加後天修養，我們之所得無人可以侵占。『失去那不能擁有的， 得到那不能奪去的。』這是我們這等人擁有的永恆。千江有水千江月，面對天地之美，我們 的『擁有』並未使別人『失去』。」 下列選項，何者符合本文所說是屬於「並未使別人失去」的「擁有」，且「不能奪去的」？', '["超凡的審美能力", "永恆不朽的人生", "壯麗的江河山川", "寧靜皎潔的明月 珍愛的親密戀人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00481', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '「楷書是字體中最整齊、最嚴謹的形式，唐人在書法上最大成就當屬『楷法』的創立，『法』 是法則、規律，從此以後，中國文字不再演化新的字體。唐以前的楷書是在追求一種法則下 進展的，三國時代的楷書仍帶有行書和隸書的筆勢，南朝楷書更加工整，但行書意味仍然濃 厚。北朝的魏碑體式多樣化，卻尚未尋找出它的規律性，隋代混同南北，成為唐楷的先驅。」 根據上文，下列選項正確的是：', '["唐人書法最大的特色是有書寫法則可以依循", "楷書的整齊嚴謹使它不得帶有行書隸書筆勢", "三國時代流行行書和隸書且沒有成熟的楷書", "南北朝楷書找到書寫規律性故表現趨勢一致 隋代能成為唐楷先驅是因其承襲南北朝發展"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00482', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '「日子就這樣過去，消磨在管山管水裡。並不固執要去做什麼事，然而想來也沒什麼大後悔。 晚上入睡前，閉目感受周遭的寧靜，我總是心懷感激。大自然如此渺漠，卻又如此可親，和 我息息相關；我無法也不願割離。在黑暗中，我彷彿聽到了宇宙生命的呼吸和訓諭。我凝神 諦聽。時間緩緩流過。」 根據上文，下列選項符合文意的是：', '["抒發時光易逝的心中感慨", "顯露對於宇宙浩瀚的迷茫", "敘寫山居歲月的恬淡安然", "呈現離群索居的寂寞孤獨 表達對自然的敬畏與戀慕"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00483', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '有位法國哲人為人道主義下定義：「一個人於河中快淹死，一百個人跳下河中相救，這一百 個人也許會因而淹死，而仍救不上那個人來。以一百比一，是件不理智的行動，我們把這種 行動叫做人道主義。因為救的不是那個『一』，而是救的那個『人』。」這種人道主義的昂 揚，是人類文明一大進程。由於人道主義的出現，率獸食人的社會才絕跡於人間。由於人道 主義的覺醒，以人祭天的犧牲才消弭於人世。 根據上文，下列選項何者屬於人道主義的表現？', '["國際紅十字會對受害者提供保護及救助", "國際貨幣基金組織長期致力於穩定匯率", "無國界醫生在衝突地區提供醫療及物資", "世界展望會幫助貧困兒童以及進行賑災 歐洲聯盟促進社會經濟發展及公民覺醒"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00484', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '「知識分子既不是調解者，也不是建立共識的人，而是全身投注於批評意識，不願接受簡單 的處方、現成的陳腔濫調，或平和寬容的肯定權勢者的說法或作法。他總是時時維持著警覺 狀態，永遠不讓似是而非的事物或約定俗成的觀念牽著鼻子走。」 根據上文，下列選項何者符合知識分子的特質？', '["不落俗套", "左右逢源", "通才碩學", "韜光養晦 慎思明辨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL)
